import type { SyntaxNodeRef } from '@lezer/common';

import type { ConvertedLezerNode } from '../../../../types/conversion-utils.js';
import type { FilterFieldComparisonOperatorNode } from '../../../../types/tree-nodes.js';
import { convertNode } from '../generic-node.js';

/**
 * Convert an (invalid) comparison operator node.
 * The validity of an operator node is checked in the statement conversion.
 * @internal
 */
export function convertComparisonOperator(
  node: SyntaxNodeRef,
  doc: string,
): ConvertedLezerNode<FilterFieldComparisonOperatorNode> {
  const { convertedNode } = convertNode(node, doc);

  if (node.name === 'InvalidComparisonOperator') {
    const textValue = convertedNode.textValue;
    convertedNode.textValue = textValue.trimEnd();
    convertedNode.range.to =
      convertedNode.range.from + convertedNode.textValue.length;
  } else if (convertedNode.value === '~' || convertedNode.value === '!~') {
    convertedNode.value =
      convertedNode.value === '~' ? 'matches-phrase' : 'not-matches-phrase';
  }

  return {
    convertedNode: convertedNode as FilterFieldComparisonOperatorNode,
    errors: [],
  };
}
